const input = $input.first().json;

// ── Normalizar campos (vienen con mayúscula del webhook) ──
const fechaRaw   = input.Fecha    || input.fecha    || "";
const horaRaw    = input.Hora     || input.hora     || "";
const duracionRaw = input.Duracion || input.duracion || 60;
const servicio   = input.Servicio || input.servicio || "";

if (!fechaRaw || !horaRaw) {
  throw new Error(`Faltan campos Fecha o Hora. Input recibido: ${JSON.stringify(input)}`);
}

const duracion = Number(duracionRaw);
const fecha    = fechaRaw.trim();   // "2026-03-20"
const hora     = horaRaw.trim();    // "16:00"

// ── Calcular hora fin ──────────────────────────────────────
const [horas, minutos] = hora.split(":").map(Number);
const totalMin = horas * 60 + minutos + duracion;
const horaFin  = String(Math.floor(totalMin / 60)).padStart(2, "0");
const minFin   = String(totalMin % 60).padStart(2, "0");

// ── Zona horaria España ────────────────────────────────────
function esVerano(dateStr) {
  const d = new Date(dateStr + "T12:00:00Z");
  const y = d.getUTCFullYear();
  const lastSunMar = new Date(Date.UTC(y, 2, 31));
  lastSunMar.setUTCDate(31 - lastSunMar.getUTCDay());
  const lastSunOct = new Date(Date.UTC(y, 9, 31));
  lastSunOct.setUTCDate(31 - lastSunOct.getUTCDay());
  return d >= lastSunMar && d < lastSunOct;
}

const offset    = esVerano(fecha) ? "+02:00" : "+01:00";
const start_time = `${fecha}T${hora}:00${offset}`;
const end_time   = `${fecha}T${horaFin}:${minFin}:00${offset}`;

return [{
  json: {
    fecha,
    hora,
    duracion,
    hora_fin:  `${horaFin}:${minFin}`,
    servicio,
    start:     start_time,
    end:       end_time,
  }
}];

