const SCHEDULE = {
  lunes:     [{ open: "10:00", close: "21:00" }],
  martes:    [{ open: "10:00", close: "21:00" }],
  miercoles: [{ open: "10:00", close: "21:00" }],
  jueves:    [{ open: "10:00", close: "21:00" }],
  viernes:   [{ open: "10:00", close: "21:00" }],
  sabado:    [{ open: "12:00", close: "20:00" }],
  domingo:   [{ open: "12:00", close: "19:00" }],
};

function timeToMin(t) {
  const [h, m] = t.split(":").map(Number);
  return h * 60 + m;
}

function minToTime(m) {
  return `${String(Math.floor(m / 60)).padStart(2, "0")}:${String(m % 60).padStart(2, "0")}`;
}

const DAY_NAMES = ["domingo","lunes","martes","miercoles","jueves","viernes","sabado"];

// ── Fuentes: busca entre todos los inputs por contenido ───
const allItems   = $input.all();
const dataOpenAI = allItems.find(i => i.json?.message?.content?.estado !== undefined)?.json;
const dataCita   = allItems.find(i => i.json?.fecha !== undefined)?.json;

if (!dataCita) {
  return [{ json: { ok: false, error: "No se encontró el item con fecha/hora/duracion. Items recibidos: " + JSON.stringify(allItems.map(i => Object.keys(i.json))) } }];
}

const fecha      = dataCita.fecha;
const horaInicio = dataCita.hora;
const duracion   = Number(dataCita.duracion);
const servicio   = dataCita.servicio || "Cita";

if (!fecha || !horaInicio || !duracion) {
  return [{ json: { ok: false, error: `Faltan campos. Recibido: fecha=${fecha}, hora=${horaInicio}, duracion=${duracion}` } }];
}

// ── 1. Validar día y horario ───────────────────────────────
const dateObj  = new Date(fecha + "T00:00:00");
const dayName  = DAY_NAMES[dateObj.getDay()];
const daySlots = SCHEDULE[dayName];

if (!daySlots) {
  return [{ json: { ok: false, error: `El centro está cerrado los ${dayName}s.`, fecha, dia: dayName } }];
}

const citaStart = timeToMin(horaInicio);
const citaEnd   = citaStart + duracion;

const dentroDeHorario = daySlots.some(slot =>
  citaStart >= timeToMin(slot.open) && citaEnd <= timeToMin(slot.close)
);

if (!dentroDeHorario) {
  const franjas = daySlots.map(s => `${s.open}–${s.close}`).join(", ");
  return [{
    json: {
      ok: false,
      error: `Fuera de horario. Los ${dayName}s abrimos de ${franjas}. Tu cita sería de ${horaInicio} a ${minToTime(citaEnd)}.`,
      fecha,
      dia: dayName,
      horario_del_centro: franjas,
    }
  }];
}

// ── 2. Bloques ocupados desde OpenAI ──────────────────────
const bloques = dataOpenAI?.message?.content?.bloques ?? [];

const busyBlocks = [];
for (const b of bloques) {
  if (b.start && b.end) {
    busyBlocks.push({
      start:  timeToMin(b.start),
      end:    timeToMin(b.end),
      titulo: b.titulo || b.title || "Ocupado",
    });
  }
}

busyBlocks.sort((a, b) => a.start - b.start);
const merged = [];
for (const block of busyBlocks) {
  if (merged.length && block.start < merged[merged.length - 1].end) {
    merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, block.end);
  } else {
    merged.push({ ...block });
  }
}

// ── 3. Comprobar solapamiento ──────────────────────────────
const conflicto = merged.find(b => citaStart < b.end && citaEnd > b.start);

if (conflicto) {
  const huecos = [];
  for (const slot of daySlots) {
    const slotStart = timeToMin(slot.open);
    const slotEnd   = timeToMin(slot.close);
    let cursor      = slotStart;

    for (const busy of merged) {
      if (busy.end <= slotStart || busy.start >= slotEnd) continue;
      const huecoFin = Math.min(busy.start, slotEnd);
      if (huecoFin - cursor >= duracion) {
        huecos.push({ desde: minToTime(cursor), hasta: minToTime(huecoFin) });
      }
      cursor = Math.max(cursor, busy.end);
    }
    if (slotEnd - cursor >= duracion) {
      huecos.push({ desde: minToTime(cursor), hasta: minToTime(slotEnd) });
    }
  }

  return [{
    json: {
      ok: false,
      error: `Ese horario no está disponible. Hay una cita de ${minToTime(conflicto.start)} a ${minToTime(conflicto.end)}.`,
      fecha,
      hora_solicitada: `${horaInicio}–${minToTime(citaEnd)}`,
      huecos_disponibles: huecos.length
        ? huecos
        : [{ mensaje: `No hay huecos de ${duracion} min disponibles ese día.` }],
    }
  }];
}

// ── 4. ✅ Todo ok ──────────────────────────────────────────
return [{
  json: {
    ok: true,
    mensaje: `Cita disponible: ${servicio} el ${fecha} de ${horaInicio} a ${minToTime(citaEnd)}.`,
    fecha,
    dia: dayName,
    servicio,
    hora_inicio:      horaInicio,
    hora_fin:         minToTime(citaEnd),
    duracion_minutos: duracion,
  }
}];

